  `User_ID` int NOT NULL,
  `Receipt_Image_URL` varchar(500) NOT NULL,
  `Rcpt_Uploaded_At` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `vendor_name` varchar(255) DEFAULT NULL,
  `receipt_date` date DEFAULT NULL,
  `total_amount` decimal(10,2) DEFAULT NULL,
  `veryfi_document_id` varchar(255) DEFAULT NULL,
  `extracted_json` text,
  `status` varchar(50) DEFAULT 'pending',
  PRIMARY KEY (`Receipt_ID`),
  KEY `idx_receipt_user` (`User_ID`),
  KEY `idx_receipt_uploaded` (`Rcpt_Uploaded_At`),
  CONSTRAINT `receipts_ibfk_1` FOREIGN KEY (`User_ID`) REFERENCES `users` (`User_ID`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
